#include "controller.h"
#include <stddef.h>

// Initialize the controller
void controller_init(controller_t *controller)
{
    if (controller == NULL) {
        return;
    }

    // Default state: safe vent-open
    controller->compressor_on = false;
    controller->vent_open = true;
    controller->state = CONTROLLER_STATE_SAFE_VENT;
    controller->has_valid_pressure = false;
    controller->last_pressure_kpa = 0;
    controller->last_pressure_ms = 0U;
    controller->has_valid_door = false;
    controller->door_closed = false;
    controller->last_door_ms = 0U;
}

// Step the controller based on input
controller_output_t controller_step(controller_t *controller, controller_input_t input)
{
    controller_output_t output;

    if (controller == NULL) {
        output.compressor_on = false;
        output.vent_open = true;
        output.state = CONTROLLER_STATE_SAFE_VENT;
        output.state_name = CONTROLLER_STATE_NAME_SAFE_VENT;
        output.changed = false;
        output.timed_out = false;
        return output;
    }

    // Initialize output with current state
    output.compressor_on = controller->compressor_on;
    output.vent_open = controller->vent_open;
    output.state = controller->state;
    output.state_name = CONTROLLER_STATE_NAME_SAFE_VENT;
    output.changed = false;
    output.timed_out = false;

    bool previous_compressor_on = controller->compressor_on;
    bool previous_vent_open = controller->vent_open;
    controller_state_t previous_state = controller->state;

    // Process the input
    switch (input.kind) {
    case CONTROLLER_INPUT_PRESSURE:
        // Update pressure freshness
        controller->has_valid_pressure = true;
        controller->last_pressure_kpa = input.pressure_kpa;
        controller->last_pressure_ms = input.now_ms;

        // Low pressure triggers compression, high pressure releases
        if (input.pressure_kpa < CONTROLLER_PRESSURE_LOW_THRESHOLD) {
            output.compressor_on = true;
            output.vent_open = false;
            controller->state = CONTROLLER_STATE_PRESSURIZING;
            output.state_name = CONTROLLER_STATE_NAME_PRESSURIZING;
        } else if (input.pressure_kpa > CONTROLLER_PRESSURE_HIGH_THRESHOLD) {
            output.compressor_on = false;
            output.vent_open = true;
            controller->state = CONTROLLER_STATE_RELIEVING;
            output.state_name = CONTROLLER_STATE_NAME_RELIEVING;
        } else {
            // In the 40-60 band, hold previous safe output
            if (previous_compressor_on != output.compressor_on) {
                output.changed = true;
            }
            if (previous_vent_open != output.vent_open) {
                output.changed = true;
            }
            controller->state = previous_state;
            output.state_name = CONTROLLER_STATE_NAME_HOLDING;
        }
        break;

    case CONTROLLER_INPUT_DOOR_OPEN:
        // Door open forces safe vent-open state
        controller->has_valid_door = true;
        controller->door_closed = false;
        controller->last_door_ms = input.now_ms;

        output.compressor_on = false;
        output.vent_open = true;
        controller->state = CONTROLLER_STATE_SAFE_VENT;
        output.state_name = CONTROLLER_STATE_NAME_SAFE_VENT;
        break;

    case CONTROLLER_INPUT_DOOR_CLOSED:
        // Door closed: check pressure band
        controller->has_valid_door = true;
        controller->door_closed = true;
        controller->last_door_ms = input.now_ms;

        if (controller->has_valid_pressure && input.pressure_kpa < CONTROLLER_PRESSURE_LOW_THRESHOLD) {
            // Low pressure with door closed: compress and vent closed
            output.compressor_on = true;
            output.vent_open = false;
            controller->state = CONTROLLER_STATE_PRESSURIZING;
            output.state_name = CONTROLLER_STATE_NAME_PRESSURIZING;
        } else if (controller->has_valid_pressure && input.pressure_kpa > CONTROLLER_PRESSURE_HIGH_THRESHOLD) {
            // High pressure with door closed: vent open
            output.compressor_on = false;
            output.vent_open = true;
            controller->state = CONTROLLER_STATE_RELIEVING;
            output.state_name = CONTROLLER_STATE_NAME_RELIEVING;
        } else if (controller->has_valid_pressure) {
            // Pressure in 40-60 band: hold previous safe output
            if (previous_compressor_on != output.compressor_on) {
                output.changed = true;
            }
            if (previous_vent_open != output.vent_open) {
                output.changed = true;
            }
            controller->state = previous_state;
            output.state_name = CONTROLLER_STATE_NAME_HOLDING;
        } else {
            // No valid pressure yet, stay in safe vent-open
            output.compressor_on = false;
            output.vent_open = true;
            controller->state = CONTROLLER_STATE_SAFE_VENT;
            output.state_name = CONTROLLER_STATE_NAME_SAFE_VENT;
        }
        break;

    case CONTROLLER_INPUT_SENSOR_TIMEOUT:
    case CONTROLLER_INPUT_INVALID_PRESSURE:
    case CONTROLLER_INPUT_INVALID_DOOR:
        // Timeout or invalid input forces safe vent-open
        output.compressor_on = false;
        output.vent_open = true;
        controller->state = CONTROLLER_STATE_SAFE_VENT;
        output.state_name = CONTROLLER_STATE_NAME_SAFE_VENT;
        break;

    case CONTROLLER_INPUT_NONE:
    default:
        // No input, hold previous state but check for timeout
        if (previous_compressor_on != output.compressor_on) {
            output.changed = true;
        }
        if (previous_vent_open != output.vent_open) {
            output.changed = true;
        }
        controller->state = previous_state;
        output.state_name = CONTROLLER_STATE_NAME_HOLDING;
        break;
    }

    // Check for timeout condition: either sensor stale for more than 1000ms
    if (controller->has_valid_pressure && input.now_ms - controller->last_pressure_ms > CONTROLLER_SENSOR_TIMEOUT_MS) {
        output.compressor_on = false;
        output.vent_open = true;
        controller->state = CONTROLLER_STATE_SAFE_VENT;
        output.state_name = CONTROLLER_STATE_NAME_SAFE_VENT;
